package exec

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	osexec "os/exec"
	"path/filepath"
	"regexp"
	"sort"
	"strconv"
	"strings"
	"sync/atomic"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
)

var errNotExecArtifact = errors.New("not an exec artifact")

const (
	execDefinitionCollection = "exec-definitions"
	execRunCollection        = "exec-runs"
	execRunAttachmentDir     = "exec-runs.d"
)

type Store struct {
	WorkingDir           string
	ExecDir              string
	DefinitionsDir       string
	RunsDir              string
	DefinitionCollection *bead.Store
	RunCollection        *bead.Store
	AgentRunner          AgentRunner
	runCounter           uint64
	graphBuilderFunc     func(string) (*docgraph.Graph, error)
}

func (s *Store) buildGraph() (*docgraph.Graph, error) {
	if s.graphBuilderFunc != nil {
		return s.graphBuilderFunc(s.WorkingDir)
	}
	return docgraph.BuildGraph(s.WorkingDir)
}

func NewStore(workingDir string) *Store {
	base := filepath.Join(workingDir, ".ddx", "exec")
	beadRoot := filepath.Join(workingDir, ".ddx")
	return &Store{
		WorkingDir:           workingDir,
		ExecDir:              base,
		DefinitionsDir:       filepath.Join(base, "definitions"),
		RunsDir:              filepath.Join(base, "runs"),
		DefinitionCollection: bead.NewStoreWithCollection(beadRoot, execDefinitionCollection),
		RunCollection:        bead.NewStoreWithCollection(beadRoot, execRunCollection),
	}
}

func (s *Store) Init() error {
	if s.DefinitionCollection != nil {
		if err := s.DefinitionCollection.Init(); err != nil {
			return err
		}
	}
	if s.RunCollection != nil {
		if err := s.RunCollection.Init(); err != nil {
			return err
		}
	}
	if err := os.MkdirAll(filepath.Join(s.WorkingDir, ".ddx", execRunAttachmentDir), 0o755); err != nil {
		return err
	}
	return os.MkdirAll(s.RunsDir, 0o755)
}

func (s *Store) ListDefinitions(artifactID string) ([]Definition, error) {
	defs, _, err := s.loadDefinitions()
	if err != nil {
		return nil, err
	}
	if artifactID == "" {
		return defs, nil
	}
	filtered := make([]Definition, 0, len(defs))
	for _, def := range defs {
		if containsString(def.ArtifactIDs, artifactID) {
			filtered = append(filtered, def)
		}
	}
	return filtered, nil
}

func findDefinitionByID(defs []Definition, definitionID string) (Definition, error) {
	var (
		best  Definition
		found bool
	)
	for _, def := range defs {
		if def.ID != definitionID {
			continue
		}
		if !found || def.CreatedAt.After(best.CreatedAt) || (def.CreatedAt.Equal(best.CreatedAt) && def.ID > best.ID) {
			best = def
			found = true
		}
	}
	if !found {
		return Definition{}, fmt.Errorf("exec definition for %q not found", definitionID)
	}
	if best.ID == "" {
		return Definition{}, fmt.Errorf("exec definition for %q is missing id", definitionID)
	}
	return best, nil
}

func (s *Store) ShowDefinition(definitionID string) (Definition, error) {
	defs, _, err := s.loadDefinitions()
	if err != nil {
		return Definition{}, err
	}
	return findDefinitionByID(defs, definitionID)
}

func (s *Store) Validate(definitionID string) (*Definition, *docgraph.Document, error) {
	defs, graph, err := s.loadDefinitions()
	if err != nil {
		return nil, nil, err
	}
	def, err := findDefinitionByID(defs, definitionID)
	if err != nil {
		return nil, nil, err
	}
	if def.ID == "" {
		return nil, nil, fmt.Errorf("exec definition is missing id")
	}
	if len(def.ArtifactIDs) == 0 {
		return nil, nil, fmt.Errorf("exec definition %q has no artifact_ids", def.ID)
	}
	if def.Executor.Kind != ExecutorKindCommand && def.Executor.Kind != ExecutorKindAgent {
		return nil, nil, fmt.Errorf("exec definition %q has invalid executor kind %q", def.ID, def.Executor.Kind)
	}
	if def.Executor.Kind == ExecutorKindCommand && len(def.Executor.Command) == 0 {
		return nil, nil, fmt.Errorf("exec definition %q has no command", def.ID)
	}
	if graph == nil {
		graph, err = s.buildGraph()
		if err != nil {
			return nil, nil, err
		}
	}
	var primary *docgraph.Document
	for _, artifactID := range def.ArtifactIDs {
		doc, ok := graph.Show(artifactID)
		if !ok {
			return nil, nil, fmt.Errorf("exec definition %q references missing artifact %q", def.ID, artifactID)
		}
		if primary == nil {
			docCopy := doc
			primary = &docCopy
		}
	}
	return &def, primary, nil
}

func (s *Store) Run(ctx context.Context, definitionID string) (RunRecord, error) {
	return s.RunWithOptions(ctx, definitionID, RunOptions{})
}

func (s *Store) RunWithOptions(ctx context.Context, definitionID string, opts RunOptions) (RunRecord, error) {
	def, doc, err := s.Validate(definitionID)
	if err != nil {
		return RunRecord{}, err
	}
	if def.Executor.Kind == ExecutorKindAgent {
		if s.AgentRunner == nil {
			return RunRecord{}, fmt.Errorf("agent runner not configured for exec definition %q", def.ID)
		}

		var promptFile, promptText string
		if len(def.Executor.Command) > 0 {
			promptFile = def.Executor.Command[0]
		} else {
			promptText = def.Executor.Env["DDX_AGENT_PROMPT"]
		}

		workDir := def.Executor.Cwd
		if workDir == "" {
			workDir = s.WorkingDir
		} else if !filepath.IsAbs(workDir) {
			workDir = filepath.Join(s.WorkingDir, workDir)
		}

		overrides := config.CLIOverrides{
			Harness: def.Executor.Env["DDX_AGENT_HARNESS"],
			Model:   def.Executor.Env["DDX_AGENT_MODEL"],
			Effort:  def.Executor.Env["DDX_AGENT_EFFORT"],
		}
		if def.Executor.TimeoutMS > 0 {
			timeout := time.Duration(def.Executor.TimeoutMS) * time.Millisecond
			overrides.Timeout = &timeout
		}
		rcfg, _ := config.LoadAndResolve(s.WorkingDir, overrides)

		sessionID := genAgentSessionID()
		runtime := agent.AgentRunRuntime{
			Prompt:     promptText,
			PromptFile: promptFile,
			Correlation: map[string]string{
				"definition_id":     def.ID,
				"artifact_ids":      strings.Join(def.ArtifactIDs, ","),
				"produces_artifact": opts.ProducesArtifact,
				"session_id":        sessionID,
			},
			WorkDir: workDir,
		}

		start := time.Now().UTC()
		agentResult, agentErr := s.AgentRunner.Run(ctx, rcfg, runtime)
		finished := time.Now().UTC()

		status := StatusSuccess
		exitCode := 0
		var stdout, stderr string
		if agentErr != nil {
			status = StatusErrored
			exitCode = 1
			stderr = agentErr.Error()
		} else {
			exitCode = agentResult.ExitCode
			stdout = strings.TrimSpace(agentResult.Output)
			stderr = strings.TrimSpace(agentResult.Stderr)
			if exitCode != 0 {
				if exitCode == -1 && strings.Contains(agentResult.Error, "timeout") {
					status = StatusTimedOut
				} else {
					status = StatusFailed
				}
			}
		}

		runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
		record := RunRecord{
			RunManifest: RunManifest{
				RunID:            runID,
				DefinitionID:     def.ID,
				ArtifactIDs:      def.ArtifactIDs,
				ProducesArtifact: opts.ProducesArtifact,
				StartedAt:        start,
				FinishedAt:       finished,
				Status:           status,
				ExitCode:         exitCode,
				MergeBlocking:    def.Required && status != StatusSuccess,
				AgentSessionID:   sessionID,

package metric

import (
	"context"
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
)

var errNotMetricArtifact = fmt.Errorf("not a metric artifact")

type Store struct {
	WorkingDir string
	execStore  *ddxexec.Store
}

func NewStore(workingDir string) *Store {
	return &Store{
		WorkingDir: workingDir,
		execStore:  ddxexec.NewStore(workingDir),
	}
}

func (s *Store) Init() error {
	if s.execStore != nil {
		return s.execStore.Init()
	}
	return nil
}

// ListArtifacts returns all MET-* artifacts in document ID order.
func (s *Store) ListArtifacts() ([]docgraph.Document, error) {
	graph, err := docgraph.BuildGraph(s.WorkingDir)
	if err != nil {
		return nil, err
	}
	ids := graph.All()
	out := make([]docgraph.Document, 0, len(ids))
	for _, id := range ids {
		if !strings.HasPrefix(id, "MET-") {
			continue
		}
		doc, ok := graph.Show(id)
		if !ok {
			continue
		}
		out = append(out, doc)
	}
	return out, nil
}

func (s *Store) Validate(metricID string) (*Definition, *docgraph.Document, error) {
	doc, err := s.loadMetricArtifact(metricID)
	if err != nil {
		return nil, nil, err
	}
	def, err := s.LoadDefinition(metricID)
	if err != nil {
		return nil, nil, err
	}
	if def.MetricID != metricID {
		return nil, nil, fmt.Errorf("metric definition %q does not target %q", def.DefinitionID, metricID)
	}
	if len(def.Command) == 0 {
		return nil, nil, fmt.Errorf("metric definition %q has no command", def.DefinitionID)
	}
	if def.Comparison == "" {
		def.Comparison = ComparisonLowerIsBetter
	}
	switch def.Comparison {
	case ComparisonLowerIsBetter, ComparisonHigherIsBetter:
	default:
		return nil, nil, fmt.Errorf("metric definition %q has invalid comparison %q", def.DefinitionID, def.Comparison)
	}
	return &def, doc, nil
}

func (s *Store) Run(ctx context.Context, metricID string) (HistoryRecord, error) {
	def, _, err := s.Validate(metricID)
	if err != nil {
		return HistoryRecord{}, err
	}
	rec, err := s.execStore.Run(ctx, def.DefinitionID)
	if err != nil {
		return HistoryRecord{}, err
	}
	return metricHistoryFromExec(rec)
}

func (s *Store) Compare(metricID, against string) (HistoryRecord, ComparisonResult, error) {
	history, err := s.History(metricID)
	if err != nil {
		return HistoryRecord{}, ComparisonResult{}, err
	}
	if len(history) == 0 {
		return HistoryRecord{}, ComparisonResult{}, fmt.Errorf("no history for metric %q", metricID)
	}
	current := history[len(history)-1]
	target, err := selectComparisonTarget(history, against)
	if err != nil {
		return HistoryRecord{}, ComparisonResult{}, err
	}
	result := comparisonFor(current.Value, target.Value, current.Comparison.Direction)
	current.Comparison = result
	return current, result, nil
}

func (s *Store) Trend(metricID string) (TrendSummary, error) {
	history, err := s.History(metricID)
	if err != nil {
		return TrendSummary{}, err
	}
	if len(history) == 0 {
		return TrendSummary{}, fmt.Errorf("no history for metric %q", metricID)
	}
	summary := TrendSummary{MetricID: metricID, Min: history[0].Value, Max: history[0].Value, Latest: history[len(history)-1].Value, Unit: history[len(history)-1].Unit, UpdatedAt: history[len(history)-1].ObservedAt}
	var sum float64
	for _, rec := range history {
		if rec.Value < summary.Min {
			summary.Min = rec.Value
		}
		if rec.Value > summary.Max {
			summary.Max = rec.Value
		}
		sum += rec.Value
		summary.UpdatedAt = rec.ObservedAt
		if rec.Unit != "" {
			summary.Unit = rec.Unit
		}
	}
	summary.Count = len(history)
	summary.Average = sum / float64(len(history))
	return summary, nil
}

func (s *Store) LoadDefinition(metricID string) (Definition, error) {
	if s.execStore == nil {
		return Definition{}, fmt.Errorf("metric store is not initialized")
	}
	defs, err := s.execStore.ListDefinitions(metricID)
	if err != nil {
		return Definition{}, err
	}
	var (
		best  Definition
		found bool
	)
	for _, def := range defs {
		if def.ID == "" {
			continue
		}
		mapped, err := metricDefinitionFromExec(def)
		if err != nil {
			return Definition{}, err
		}
		if mapped.MetricID != metricID || !mapped.Active {
			continue
		}
		if !found || mapped.CreatedAt.After(best.CreatedAt) || (mapped.CreatedAt.Equal(best.CreatedAt) && mapped.DefinitionID > best.DefinitionID) {
			best = mapped
			found = true
		}
	}
	if !found {
		return Definition{}, fmt.Errorf("metric definition for %q not found", metricID)
	}
	if best.DefinitionID == "" {
		return Definition{}, fmt.Errorf("metric definition for %q is missing definition_id", metricID)
	}
	return best, nil
}

func (s *Store) SaveDefinition(def Definition) error {
	if def.DefinitionID == "" {
		return fmt.Errorf("definition_id is required")
	}
	if def.MetricID == "" {
		return fmt.Errorf("metric_id is required")
	}
	if s.execStore == nil {
		return fmt.Errorf("metric store is not initialized")
	}
	return s.execStore.SaveDefinition(metricDefinitionToExec(def))
}

func (s *Store) AppendHistory(rec HistoryRecord) error {
	if s.execStore == nil {
		return fmt.Errorf("metric store is not initialized")
	}
	return s.execStore.SaveRunRecord(metricHistoryToRun(rec))
}

func (s *Store) History(metricID string) ([]HistoryRecord, error) {
	if s.execStore == nil {
		return []HistoryRecord{}, fmt.Errorf("metric store is not initialized")
	}
	records, err := s.execStore.History(metricID, "")
	if err != nil {
		return nil, err
	}
	out := make([]HistoryRecord, 0, len(records))
	for _, rec := range records {
		mapped, err := metricHistoryFromExec(rec)
		if err != nil {
			return nil, err
		}
		if mapped.MetricID == metricID {
			out = append(out, mapped)
		}
	}
	return out, nil
}

func (s *Store) loadMetricArtifact(metricID string) (*docgraph.Document, error) {
	if !strings.HasPrefix(metricID, "MET-") {
		return nil, fmt.Errorf("%w: %s", errNotMetricArtifact, metricID)
	}
	graph, err := docgraph.BuildGraph(s.WorkingDir)
	if err != nil {
		return nil, err
	}
	doc, ok := graph.Show(metricID)
	if !ok {
		return nil, fmt.Errorf("metric artifact %q not found", metricID)
	}
	return &doc, nil
}

func selectComparisonTarget(history []HistoryRecord, against string) (HistoryRecord, error) {
	switch against {
	case "", "latest":
		return history[len(history)-1], nil
	case "baseline":
		return history[0], nil
	default:
		for _, rec := range history {
			if rec.RunID == against {
				return rec, nil
			}
		}
		return HistoryRecord{}, fmt.Errorf("comparison target %q not found", against)
	}
}

